"""A tiny command-line calculator."""


def add(a, b):
    return a + b


def subtract(a, b):
    return a - b


def multiply(a, b):
    return a * b


def divide(a, b):
    if b == 0:
        raise ValueError("Cannot divide by zero")
    return a / b


def main():
    print("Welcom to Calculator!")
    print("2 + 2 =", add(2, 2))


if __name__ == "__main__":
    main()

